package com.blissless.tensei.ui.screens.exploreimport androidx.compose.animation.AnimatedVisibilityimport androidx.compose.animation.core.FastOutSlowInEasingimport androidx.compose.animation.core.tweenimport androidx.compose.animation.fadeInimport androidx.compose.animation.fadeOutimport androidx.compose.animation.slideInVerticallyimport androidx.compose.animation.slideOutVerticallyimport androidx.compose.foundation.backgroundimport androidx.compose.foundation.interaction.collectIsDraggedAsStateimport androidx.compose.foundation.layout.Arrangementimport androidx.compose.foundation.layout.Boximport androidx.compose.foundation.layout.Columnimport androidx.compose.foundation.layout.Rowimport androidx.compose.foundation.layout.Spacerimport androidx.compose.foundation.layout.fillMaxSizeimport androidx.compose.foundation.layout.fillMaxWidthimport androidx.compose.foundation.layout.heightimport androidx.compose.foundation.layout.paddingimport androidx.compose.foundation.layout.sizeimport androidx.compose.foundation.layout.statusBarsPaddingimport androidx.compose.foundation.layout.widthimport androidx.compose.foundation.pager.HorizontalPagerimport androidx.compose.foundation.pager.rememberPagerStateimport androidx.compose.foundation.shape.CircleShapeimport androidx.compose.foundation.shape.RoundedCornerShapeimport androidx.compose.material.icons.Iconsimport androidx.compose.material.icons.filled.Bookmarkimport androidx.compose.material.icons.filled.BookmarkBorderimport androidx.compose.material.icons.filled.Searchimport androidx.compose.material.icons.outlined.Infoimport androidx.compose.material.icons.outlined.PlayArrowimport androidx.compose.material3.Buttonimport androidx.compose.material3.ButtonDefaultsimport androidx.compose.material3.Iconimport androidx.compose.material3.IconButtonimport androidx.compose.material3.MaterialThemeimport androidx.compose.material3.Textimport androidx.compose.runtime.Composableimport androidx.compose.runtime.DisposableEffectimport androidx.compose.runtime.LaunchedEffectimport androidx.compose.runtime.derivedStateOfimport androidx.compose.runtime.getValueimport androidx.compose.runtime.mutableIntStateOfimport androidx.compose.runtime.mutableStateOfimport androidx.compose.runtime.rememberimport androidx.compose.runtime.rememberCoroutineScopeimport androidx.compose.runtime.setValueimport androidx.compose.ui.Alignmentimport androidx.compose.ui.Modifierimport androidx.compose.ui.draw.clipimport androidx.compose.ui.graphics.Brushimport androidx.compose.ui.graphics.Colorimport androidx.compose.ui.layout.ContentScaleimport androidx.compose.ui.platform.LocalContextimport androidx.compose.ui.text.font.FontWeightimport androidx.compose.ui.text.style.TextAlignimport androidx.compose.ui.text.style.TextOverflowimport androidx.compose.ui.unit.dpimport coil.compose.AsyncImageimport coil.request.ImageRequestimport com.blissless.tensei.Rimport com.blissless.tensei.data.models.ExploreAnimeimport kotlinx.coroutines.Jobimport kotlinx.coroutines.delayimport kotlinx.coroutines.launch@Composablefun FeaturedCarousel(    animeList: List<ExploreAnime>,    onAnimeClick: (ExploreAnime) -> Unit,    onStatusClick: (ExploreAnime) -> Unit,    onPlayClick: (ExploreAnime) -> Unit,    onInfoClick: (ExploreAnime) -> Unit,    onSearchClick: () -> Unit = {},    animeStatusMap: Map<Int, String> = emptyMap(),    preferEnglishTitles: Boolean = true,    isOled: Boolean = false,    isDialogOpen: Boolean = false,    autoScrollEnabled: Boolean = true,    isVisible: Boolean = true) {    if (animeList.isEmpty()) return    val actualCount = animeList.size    val pagerState = rememberPagerState(        initialPage = actualCount * 100,        pageCount = { actualCount * 200 }    )        val context = LocalContext.current    val scope = rememberCoroutineScope()    val isDragged by pagerState.interactionSource.collectIsDraggedAsState()    var autoScrollJob by remember { mutableStateOf<Job?>(null) }    var headerVisible by remember { mutableStateOf(true) }    var pageWhenScrollStarted by remember { mutableIntStateOf(pagerState.currentPage) }    var isHeaderSwiping by remember { mutableStateOf(false) }    var timerResetSignal by remember { mutableIntStateOf(0) }    LaunchedEffect(pagerState.isScrollInProgress, pagerState.currentPageOffsetFraction) {        if (pagerState.isScrollInProgress) {            pageWhenScrollStarted = pagerState.currentPage        } else if (pagerState.currentPage != pageWhenScrollStarted) {            headerVisible = false            delay(80)            headerVisible = true            pageWhenScrollStarted = pagerState.currentPage        }    }    LaunchedEffect(isDragged) {        if (isDragged) {            timerResetSignal++        }    }    LaunchedEffect(autoScrollEnabled, isVisible, isHeaderSwiping, isDialogOpen, timerResetSignal) {        if (autoScrollEnabled && isVisible && !isHeaderSwiping && !isDialogOpen) {            while (true) {                delay(4500)                if (isHeaderSwiping) continue                headerVisible = false                delay(80)                headerVisible = true                                autoScrollJob = scope.launch {                    try {                        val targetPage = pagerState.currentPage + 1                        pagerState.animateScrollToPage(targetPage)                    } catch (_: Exception) {}                }                autoScrollJob?.join()                                delay(300)            }        }    }    DisposableEffect(Unit) {        onDispose { autoScrollJob?.cancel() }    }    Box(modifier = Modifier.fillMaxWidth().height(520.dp)) {        HorizontalPager(            state = pagerState,            modifier = Modifier.fillMaxSize(),            pageSpacing = 0.dp,            userScrollEnabled = true,            beyondViewportPageCount = 0        ) { page ->            val anime = animeList[page % actualCount]                        Box(modifier = Modifier.fillMaxSize().background(Color.Black)) {                AsyncImage(                    model = ImageRequest.Builder(context)                        .data(anime.cover)                        .memoryCacheKey(anime.cover)                        .crossfade(true)                        .build(),                    contentDescription = null,                    contentScale = ContentScale.Crop,                    modifier = Modifier.fillMaxSize()                )                Box(                    modifier = Modifier.fillMaxSize().background(                        Brush.verticalGradient(                            listOf(                                Color.Black.copy(alpha = 0.3f),                                Color.Transparent,                                Color.Black.copy(alpha = 0.7f),                                Color.Black.copy(alpha = 0.95f)                            )                        )                    )                )            }        }        Box(            modifier = Modifier.fillMaxSize(),            contentAlignment = Alignment.Center        ) {            // Top header with app logo and search icon            Box(                modifier = Modifier                    .fillMaxWidth()                    .background(                        Brush.verticalGradient(                            listOf(                                Color.Black.copy(alpha = 0.6f),                                Color.Transparent                            )                        )                    )                    .padding(start = 16.dp, end = 16.dp, top = 28.dp)                    .align(Alignment.TopCenter)            ) {                Row(                    modifier = Modifier.fillMaxWidth(),                    horizontalArrangement = Arrangement.SpaceBetween,                    verticalAlignment = Alignment.CenterVertically                ) {                    AsyncImage(                        model = com.blissless.tensei.R.mipmap.ic_launcher_round,                        contentDescription = "App",                        modifier = Modifier.size(32.dp).clip(CircleShape)                    )                    IconButton(onClick = onSearchClick) {                        Icon(                            imageVector = Icons.Default.Search,                            contentDescription = "Search",                            tint = Color.White,                            modifier = Modifier.size(24.dp)                        )                    }                }            }            Box(                modifier = Modifier.fillMaxWidth().padding(horizontal = 16.dp).align(Alignment.BottomCenter),                contentAlignment = Alignment.BottomCenter            ) {            val currentAnime by remember {                derivedStateOf { animeList[pagerState.currentPage % actualCount] }            }            AnimatedVisibility(                visible = headerVisible,                enter = fadeIn(animationSpec = tween(400, easing = FastOutSlowInEasing)) +                        slideInVertically(                            animationSpec = tween(400, easing = FastOutSlowInEasing),                            initialOffsetY = { it / 2 }                        ),                exit = fadeOut(animationSpec = tween(150, easing = FastOutSlowInEasing)) +                        slideOutVertically(                            animationSpec = tween(150, easing = FastOutSlowInEasing),                            targetOffsetY = { it / 2 }                        )            ) {                Column(                    horizontalAlignment = Alignment.CenterHorizontally                ) {                    val displayTitle = (if (preferEnglishTitles && currentAnime.titleEnglish != null) currentAnime.titleEnglish else currentAnime.title) ?: "Unknown"                    Text(                        text = displayTitle,                        color = Color.White,                        style = MaterialTheme.typography.titleLarge,                        fontWeight = FontWeight.Bold,                        maxLines = 2,                        overflow = TextOverflow.Ellipsis,                        textAlign = TextAlign.Center                    )                                        Spacer(modifier = Modifier.height(8.dp))                                        Row(                        horizontalArrangement = Arrangement.Center,                        verticalAlignment = Alignment.CenterVertically                    ) {                        val avgScore = currentAnime.averageScore                        val format = currentAnime.format                        currentAnime.year?.let { year ->                            Text(text = year.toString(), color = Color.White.copy(alpha = 0.8f), style = MaterialTheme.typography.bodySmall)                            Text(text = " • ", color = Color.White.copy(alpha = 0.5f), style = MaterialTheme.typography.bodySmall)                        }                        val formatText = when (format?.uppercase()) {                            "MOVIE" -> "Movie"                            "ONA", "OVA", "TV" -> "Series"                            else -> "Series"                        }                        Text(text = formatText, color = Color.White.copy(alpha = 0.8f), style = MaterialTheme.typography.bodySmall)                        if (avgScore != null) {                            Text(text = " • ", color = Color.White.copy(alpha = 0.5f), style = MaterialTheme.typography.bodySmall)                            val scoreValue = avgScore / 10.0                            val scoreFormatted = "%,.1f".format(scoreValue).replace(".", ",")                            Text(                                text = "★ $scoreFormatted",                                color = Color(0xFFFFD700),                                style = MaterialTheme.typography.bodySmall,                                fontWeight = FontWeight.Bold                            )                        }                    }                                        Spacer(modifier = Modifier.height(16.dp))                                        Row(                        horizontalArrangement = Arrangement.spacedBy(8.dp),                        verticalAlignment = Alignment.CenterVertically                    ) {                        val currentStatus = animeStatusMap[currentAnime.id]                        val isSaved = currentStatus != null                        val statusColor = when (currentStatus) {                            "COMPLETED" -> Color(0xFF4CAF50)                            "CURRENT" -> Color(0xFF2196F3)                            "PLANNING" -> Color(0xFF9C27B0)                            "PAUSED" -> Color(0xFFFFC107)                            "DROPPED" -> Color(0xFFF44336)                            else -> Color.White                        }                                                IconButton(                            onClick = { onStatusClick(currentAnime) },                            modifier = Modifier.size(40.dp)                        ) {                            Icon(                                if (isSaved) Icons.Default.Bookmark else Icons.Default.BookmarkBorder,                                contentDescription = "Save",                                tint = if (isSaved) statusColor else Color.White,                                modifier = Modifier.size(22.dp)                            )                        }                                                Button(                            onClick = { onPlayClick(currentAnime) },                            modifier = Modifier                                .height(48.dp)                                .background(                                    brush = Brush.horizontalGradient(                                        colors = listOf(                                            MaterialTheme.colorScheme.primary,                                            MaterialTheme.colorScheme.tertiary                                        )                                    ),                                    shape = RoundedCornerShape(12.dp)                                ),                            shape = RoundedCornerShape(12.dp),                            colors = ButtonDefaults.buttonColors(                                containerColor = Color.Transparent,                                contentColor = MaterialTheme.colorScheme.onPrimary                            )                        ) {                            Icon(                                Icons.Outlined.PlayArrow,                                contentDescription = "Watch",                                modifier = Modifier.size(24.dp)                            )                            Spacer(modifier = Modifier.width(6.dp))                            Text("Watch Now", style = MaterialTheme.typography.labelMedium)                        }                                                IconButton(                            onClick = { onInfoClick(currentAnime) },                            modifier = Modifier.size(40.dp)                        ) {                            Icon(                                Icons.Outlined.Info,                                contentDescription = "Info",                                tint = Color.White,                                modifier = Modifier.size(20.dp)                            )                        }                    }                }            }        }        }    }}